import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { MarkaziaVouchersComponent } from './markazia-vouchers.component';

const routes: Routes = [
  { path: '', component: MarkaziaVouchersComponent }
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class MarkaziaVouchersRoutingModule { }
