import { DatePipe } from '@angular/common';
import { Component } from '@angular/core';
import { CommonService } from '../../../../services/common.service';
import { NgbActiveModal, NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { FormBuilder, FormGroup } from '@angular/forms';
import { CollectService } from '../collect/services/collect.service';
import { MarkaziaVoucherService } from './services/markazia-voucher.service';
import { TableColumn, TableConfig } from '../../../../shared/components/table-advanced/table-advanced-interfaces';
import { catchError, debounceTime, distinctUntilChanged, forkJoin, of } from 'rxjs';
import { GenerateVoucherComponent } from './components/generate-voucher/generate-voucher.component';
import { NgxSpinnerService } from 'ngx-spinner';
import { GeneralService } from '../../../../services/general.service';
import { ExcelService } from '../../../../services/excel.service';
import { ConfirmModalComponent } from '../../../../shared/components/confirm-modal/confirm-modal.component';
import { ModalMessageComponent } from '../../../../shared/components/modal-message/modal-message.component';

@Component({
  selector: 'app-markazia-vouchers',
  templateUrl: './markazia-vouchers.component.html',
  styleUrls: ['./markazia-vouchers.component.scss']
})
export class MarkaziaVouchersComponent {
  brandsList = [];
  vouchersList = [];
  statusList = [];
  vouchersInfo;
  filterForm: FormGroup;
  filterParams;
  pageNo = 1;
  total = 0;
  limit = 6;
  loading = false;
  tableConfig: TableConfig = {
    paging: true,
    filter: {
      Sort: 1,
      PageSize: this.limit,
    },
  };
  tableColumns: TableColumn[] = [];
  constructor(
    private _vocuherService: MarkaziaVoucherService,
    private fb: FormBuilder,
    private _modalService: NgbModal,
    private _datePipe: DatePipe,
    private _spinner: NgxSpinnerService,
    private _excelService: ExcelService,
  ) { }
  ngOnInit() {
    this.initTableColumns();
    this.initFilterParams();
    //this.getMarkaziaVouchers()
    this.getLookups();
    this.filterForm.get('date').setValue([this.getMonthStartDate(), this.getMonthEndDate()]);
  }
  getLookups() {
    const brands = this._vocuherService.getBrands('').pipe(catchError(error => of(error)));
    const status = this._vocuherService.getLookup(`?lookupTypeId=39`).pipe(catchError(error => of(error)));
    forkJoin([brands, status]).subscribe(data => {
      this.brandsList = data[0];
      this.statusList = data[1].data.map(x => { return { ...x, text: x?.name[0]?.lookupName } });
    })
  }
  initFilterParams() {
    this.filterForm = this.fb.group({
      id: [''],
      sequence: [''],
      brandId: [null],
      campaign: [''],
      date: [''],
      status: [null],
    })
    this.filterForm.valueChanges.pipe(debounceTime(500), distinctUntilChanged()).subscribe(value => {
      this.pageNo = 1;
      let dateObj = { fromDate: '', toDate: '' };
      let formValues;
      if (value['date']) {
        dateObj['fromDate'] = this._datePipe.transform(value['date'][0], 'yyyy-MM-dd');
        dateObj['toDate'] = this._datePipe.transform(value['date'][1], 'yyyy-MM-dd');;
      }
      formValues = { ...value, ...dateObj };
      delete formValues['date'];
      if (formValues.brandId == null) {
        formValues = { ...formValues, brandId: '' }
      }
      if (formValues.status == null) {
        formValues = { ...formValues, status: '' }
      }
      this.filterParams = '?' + new URLSearchParams(formValues).toString();
      this.getMarkaziaVouchers()
    })
  }
  generateVoucher() {
    const modalRef = this._modalService.open(GenerateVoucherComponent, { modalDialogClass: 'generate-vouchers-size'});
    modalRef.componentInstance.eventData.subscribe(x => {
      if (x) {
        this.getMarkaziaVouchers();
      }
    })
  }
  confirmDeleteVoucher(voucherId) {
    const modalRef = this._modalService.open(ConfirmModalComponent, { size: 'md' });
    modalRef.componentInstance.data = { body: 'Are you sure want to delete this voucher?' }
    modalRef.componentInstance.eventData.subscribe(x => {
      if (x) {
        this.deleteVoucher(voucherId);
      }
    })
  }
  deleteVoucher(voucherId) {
    this._spinner.show();
    let formData = new FormData();
    formData.append('VoucherId', voucherId)
    this._vocuherService.deleteMarkaziaVouchers(formData).subscribe((response: any) => {
      if (response.isSuccess) {
        this.responseModal('success', 'Voucher deleted successfully!');
        this.getMarkaziaVouchers();
      }
    }).add(() => this._spinner.hide())
  }
  responseModal(type, message) {
    const ref = this._modalService.open(ModalMessageComponent);
    ref.componentInstance.type = type;
    ref.componentInstance.dismissOnlyActive = true;
    if (type == 'success')
      ref.componentInstance.message = message;
    else
      ref.componentInstance.messageError = message;
  }
  getMarkaziaVouchers() {
    this.vouchersList = [];
    this.tableConfig = { ...this.tableConfig, isLoading: true };
    let defaultParams = `pageSize=${this.tableConfig.filter.PageSize}&pageNo=${this.pageNo - 1}&sort=${this.tableConfig.filter.Sort}`;
    let params;
    if (this.filterParams) params = `${this.filterParams}&${defaultParams}`; else params = `?${defaultParams}`;
    this._vocuherService.getMarkaziaVoucherList(params).subscribe((response: any) => {
      this.vouchersList = response.data;
      this.total = response.totalRecordCount;
      this.vouchersInfo = response.info;
    }).add(() => this.tableConfig = { ...this.tableConfig, isLoading: false })
  }
  exportToExcel() {
    this._spinner.show();
    let params;
    let defaultParams = `pageSize=1000&pageNo=0`;
    if (this.filterParams) params = `${this.filterParams}&${defaultParams}`; else params = `?${defaultParams}`;
    this._vocuherService.getMarkaziaVoucherList(params).subscribe((response: any) => {
      this.generateExcel(response.data);
    }).add(() => this._spinner.hide())
  }
  generateExcel(dataList: []) {
    let headings = [['Voucher ID', 'Voucher Sequence Number', 'Amount JOD', 'Brand', 'Campaign', 'Issuance Date', 'Validity From', 'Validity From', 'Status']];
    let data = dataList.map((x: any) => {
      return {
        a: x?.markaziaVoucherID,
        b: x?.markaziaVSequence,
        bb: x?.markaziaVAmount,
        c: x?.brand.brand,
        d: x?.markaziaVCampaign,
        e: this._datePipe.transform(x?.createdAt, 'mediumDate'),
        f: this._datePipe.transform(x?.markaziaVValidityFrom, 'mediumDate'),
        ff: this._datePipe.transform(x?.markaziaVValidityTo, 'mediumDate'),
        g: x?.statusObj[0].lookupName,
      }
    })
    this._excelService.exportToExcel(data, headings, 'Vouchers');
  }
  onSortChange(sort: any) {
    if (sort?.direction && sort?.column) {
      switch (sort.column) {
        case 'markaziaVoucherID':
          this.tableConfig.filter.Sort = sort.direction === 'desc' ? 3 : 2;
          break;
        case 'markaziaVSequence':
          this.tableConfig.filter.Sort = sort.direction === 'desc' ? 5 : 4;
          break;
        case 'markaziaVAmount':
          this.tableConfig.filter.Sort = sort.direction === 'desc' ? 7 : 6;
          break;
        case 'brand.brand':
          this.tableConfig.filter.Sort = sort.direction === 'desc' ? 9 : 8;
          break;
        case 'markaziaVCampaign':
          this.tableConfig.filter.Sort = sort.direction === 'desc' ? 11 : 10;
          break;
        case 'createdAt':
          this.tableConfig.filter.Sort = sort.direction === 'desc' ? 13 : 12;
          break;
        case 'statusObj[0].lookupName':
          this.tableConfig.filter.Sort = sort.direction === 'desc' ? 15 : 14;
          break;
        default:
          break;
      }
    } else {
      this.tableConfig.filter.Sort = 1;
    }
    this.getMarkaziaVouchers();
  }
  onPageChange(page: number) {
    this.pageNo = page;
    this.getMarkaziaVouchers();
  }
  initTableColumns() {
    this.tableColumns = [
      { key: 'markaziaVoucherID', label: 'Vocuher ID', canSort: true, },
      { key: 'markaziaVSequence', label: 'Voucher Sequence Number', canSort: true, },
      { key: 'markaziaVAmount', label: 'Amount JOD', canSort: true, currency: { decimalFormat: '2.3-3', appendText: ' JOD' } },
      { key: 'brand.brand', label: 'Brand', canSort: true, placeholder: '---' },
      { key: 'markaziaVCampaign', label: 'Campaign', canSort: true, },
      { key: 'createdAt', label: 'Issuance Date', canSort: true, dateFormat: 'mediumDate' },
      { key: 'validity', label: 'Validity From-To' },
      { key: 'statusObj[0].lookupName', label: 'Status', canSort: true, },
      { key: 'action', label: 'Action', },
    ];
  }
  getMonthEndDate() {
    var today = new Date();
    var endOfMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0);
    return endOfMonth;
  }
  getMonthStartDate() {
    var today = new Date();
    var startOfMonth = new Date(today.getFullYear(), today.getMonth(), 1);
    return startOfMonth;
  }
}
