import { Component, EventEmitter } from '@angular/core';
import { MarkaziaVoucherService } from '../../services/markazia-voucher.service';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { DatePipe } from '@angular/common';
import { NgbActiveModal, NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { catchError, forkJoin, of } from 'rxjs';
import { ModalMessageComponent } from '../../../../../../shared/components/modal-message/modal-message.component';
import { ConfirmModalComponent } from '../../../../../../shared/components/confirm-modal/confirm-modal.component';
import { TableColumn, TableConfig } from '../../../../../../shared/components/table-advanced/table-advanced-interfaces';
import { GeneralService } from '../../../../../../services/general.service';
import { ExcelService } from '../../../../../../services/excel.service';
import { NgxSpinnerService } from 'ngx-spinner';

@Component({
  selector: 'app-generate-voucher',
  templateUrl: './generate-voucher.component.html',
  styleUrls: ['./generate-voucher.component.scss']
})
export class GenerateVoucherComponent {
  brandsList = [];
  costCenterList = [];
  voucherForm: FormGroup;
  eventData = new EventEmitter();
  pageNo = 1;
  total = 0;
  limit = 6;
  tableConfig: TableConfig = {
    paging: false,
    filter: {
      Sort: 1,
      PageSize: this.limit,
    },
  };
  tableColumns: TableColumn[] = [];
  vouchersList = [];
  constructor(
    private _vocuherService: MarkaziaVoucherService,
    private fb: FormBuilder,
    private _modalService: NgbModal,
    private _datePipe: DatePipe,
    public _activeModal: NgbActiveModal,
    public _excelService: ExcelService,
    public _spinner: NgxSpinnerService,

  ) { }
  ngOnInit() {
    this.initForm();
    this.getLookups();
    this.initTableColumns();
  }
  getLookups() {
    const brands = this._vocuherService.getBrands('').pipe(catchError(error => of(error)));
    const costCenter = this._vocuherService.getCostCenter(`?StatusId=2001&CostCenterType=38001&PageSize=1000`).pipe(catchError(error => of(error)));
    forkJoin([brands, costCenter]).subscribe(data => {
      this.brandsList = data[0];
      this.costCenterList = data[1].data;
    })
  }
  initForm() {
    this.voucherForm = this.fb.group({
      brandId: [null, [Validators.required]],
      campaign: ['', [Validators.required]],
      costCenterId: [null, [Validators.required]],
      numberofVouchers: ['', [Validators.required, Validators.min(1)]],
      amountperVoucher: ['', [Validators.required, Validators.min(1)]],
      validityFrom: [''],
      validityTo: [''],
      date: ['', [Validators.required]]
    })
  }
  confirmModal() {
    const ref = this._modalService.open(ConfirmModalComponent, { centered: true });
    ref.componentInstance.data = { body: 'Are you sure you want to generate vouchers?' }
    ref.componentInstance.eventData.subscribe(x => {
      if (x)
        this.generateVoucher();
    })
  }
  generateVoucher() {
    if (this.f.invalid) {
      this.f.markAllAsTouched();
      return
    }
    this.vouchersList = [];
    this._spinner.show();
    let formData = new FormData();
    let formValue = { ...this.f.value };
    formData.append('BrandId', formValue?.brandId);
    formData.append('Campaign', formValue?.campaign);
    formData.append('CostCenterId', formValue?.costCenterId);
    formData.append('NumberofVouchers', formValue?.numberofVouchers);
    formData.append('AmountperVoucher', formValue?.amountperVoucher);
    formData.append('ValidityFrom', this._datePipe.transform(formValue.date[0], 'yyyy-MM-dd'));
    formData.append('ValidityTo', this._datePipe.transform(formValue.date[1], 'yyyy-MM-dd'));
    this._vocuherService.generateVoucher(formData).subscribe({
      next: response => {
        if (response.isSuccess) {
          this.responseModal('success', 'The voucher has been generated successfully');
          this.eventData.emit(true);
          this.f.reset();
          this.vouchersList = response.data;
          this.total = this.vouchersList.length;
        }
      },
      error: err => {
        this.responseModal('error', err?.error?.errors);
      }
    }).add(() => this._spinner.hide());
  }
  exportToExcel() {
    var headings = [['Vocuher ID', 'Voucher Sequence Number', 'Amount JOD', 'Brand', 'Campaign', 'Issuance Date', 'Validity From', 'Validity To']];
    let data = this.vouchersList.map(x => {
      return {
        markaziaVoucherID: x?.markaziaVoucherID,
        markaziaVSequence: x?.markaziaVSequence,
        markaziaVAmount: x?.markaziaVAmount,
        brand: x?.brand?.brand,
        markaziaVCampaign: x?.markaziaVCampaign,
        createdAt: this._datePipe.transform(x?.createdAt, 'mediumDate'),
        from: this._datePipe.transform(x?.markaziaVValidityFrom, 'mediumDate'),
        to: this._datePipe.transform(x?.markaziaVValidityTo, 'mediumDate'),
      }
    })
    this._excelService.exportToExcel(data, headings, 'GeneratedVouchers');
  }
  onSortChange(sort: any) {
    if (sort?.direction && sort?.column) {
      switch (sort.column) {
      }
    } else {
      this.tableConfig.filter.Sort = 1;
    }
  }
  onPageChange(page: number) {
    this.pageNo = page;
  }
  initTableColumns() {
    this.tableColumns = [
      { key: 'markaziaVoucherID', label: 'Vocuher ID', },
      { key: 'markaziaVSequence', label: 'Voucher Sequence Number', },
      { key: 'markaziaVAmount', label: 'Amount JOD', currency: { decimalFormat: '2.3-3', appendText: ' JOD' } },
      { key: 'brand.brand', label: 'Brand', placeholder: '---' },
      { key: 'markaziaVCampaign', label: 'Campaign', },
      { key: 'createdAt', label: 'Issuance Date', dateFormat: 'mediumDate' },
      { key: 'validity', label: 'Validity From-To' },
    ];
  }
  responseModal(type, message) {
    const ref = this._modalService.open(ModalMessageComponent);
    ref.componentInstance.type = type;
    ref.componentInstance.dismissOnlyActive = true;
    if (type == 'success')
      ref.componentInstance.message = message;
    else
      ref.componentInstance.messageError = message;
  }
  get f() {
    return this.voucherForm;
  }
}
